const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    req_id: body.req_id,
    title: body.title,
    description: body.description || '',
    scope: body.scope || 'server-go',
    round: 0,
    total_tokens: 0,
    start_time: Date.now(),
    max_rounds: 3,
    max_duration_ms: 3600000,
    max_tokens: 500000
  }
}];

const resp = $input.first().json;
const headers = resp.headers || {};
const sessionId = headers['mcp-session-id'] || headers['Mcp-Session-Id'] || '';
return [{
  json: {
    ...$node['Parse Request'].json,
    _session_id: sessionId,
    _bkd_url: 'https://bkd-launcher--admin-jbcnet--weifashi.coder.tbc.5ok.co/api/mcp',
    _coder_token: 'GRvtsFrbNV-7fX1P2rwfDRKwnmXsSYQEn'
  }
}];

const raw = $input.first().json;
const state = $node['Parse Init'].json;

// Parse SSE
let respData = raw;
if (typeof raw === 'string' || (typeof raw.data === 'string')) {
  const str = typeof raw === 'string' ? raw : raw.data;
  const lines = str.split('\n').filter(l => l.startsWith('data:'));
  if (lines.length > 0) {
    try { respData = JSON.parse(lines[lines.length - 1].replace('data: ', '')); } catch(e) {}
  }
}

let data = {};
try {
  const text = respData.result?.content?.[0]?.text || '{}';
  data = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  data = respData;
}
const available = data.availableSlots || 0;
return [{
  json: {
    ...state,
    _available_slots: available,
    _capacity_ok: available >= 2
  }
}];

const s = $node['Parse Request'].json;
return [{
  json: {
    projectId: 'ttposhwt',
    title: '[' + s.req_id + '] P0 Contract Design',
    prompt: 'Requirement ' + s.req_id + ': ' + s.title + '\n\nDescription: ' + s.description + '\nScope: ' + s.scope + '\n\nTask: Design the API contract for this requirement.\n- Define endpoint paths, methods, request/response schemas\n- Output as contract.spec.yaml\n- Save to the worktree\n- When done, move issue to review status',
    engineType: 'claude-code',
    tags: ['p0', s.req_id],
    timeoutMs: 900000,
    useWorktree: true
  }
}];

const s = $node['Parse Request'].json;
return [{
  json: {
    projectId: 'ttposhwt',
    title: '[' + s.req_id + '] P1 Spec Split',
    prompt: 'Requirement ' + s.req_id + ': ' + s.title + '\n\nTask: Split the contract into three specs:\n1. dev.spec.md - implementation details and unit test requirements\n2. contract.spec.yaml - API schema validation rules\n3. ac.spec.yaml - acceptance test scenarios (Given/When/Then)\n\nIMPORTANT: The ac.spec.yaml is LOCKED after this step. It must not be modified by the AI during development. It serves as the acceptance criteria.\n\nWhen done, move issue to review status.',
    engineType: 'claude-code',
    tags: ['p1', s.req_id],
    timeoutMs: 900000,
    useWorktree: true
  }
}];

const result = $input.first().json;
const state = $node['Parse Request'].json;
const elapsed = Date.now() - state.start_time;
const tokensUsed = result.output?.tokens_used || 0;
const tokens = (state.total_tokens || 0) + tokensUsed;

return [{
  json: {
    req_id: state.req_id,
    title: state.title,
    description: state.description,
    scope: state.scope,
    round: state.round + 1,
    total_tokens: tokens,
    start_time: state.start_time,
    elapsed_ms: elapsed,
    max_rounds: state.max_rounds,
    max_duration_ms: state.max_duration_ms,
    max_tokens: state.max_tokens,
    success: result.success === true,
    layer_results: result.output?.layer_results || {},
    failed_layer: result.output?.failed_layer || null,
    error_summary: result.output?.error_summary || result.error || null,
    issueId: result.issueId
  }
}];

const s = $input.first().json;
const tripped = (
  s.round >= s.max_rounds ||
  s.elapsed_ms >= s.max_duration_ms ||
  s.total_tokens >= s.max_tokens
);
const reason = [];
if (s.round >= s.max_rounds) reason.push('rounds ' + s.round + '/' + s.max_rounds);
if (s.elapsed_ms >= s.max_duration_ms) reason.push('time ' + Math.round(s.elapsed_ms/1000) + 's/' + s.max_duration_ms/1000 + 's');
if (s.total_tokens >= s.max_tokens) reason.push('tokens ' + s.total_tokens + '/' + s.max_tokens);

return [{
  json: {
    ...s,
    breaker_tripped: tripped,
    breaker_reason: reason.join(', ') || 'none'
  }
}];

const s = $input.first().json;
return [{
  json: {
    status: 'breaker_tripped',
    req_id: s.req_id,
    title: s.title,
    round: s.round,
    total_tokens: s.total_tokens,
    elapsed_ms: s.elapsed_ms,
    breaker_reason: s.breaker_reason,
    failed_layer: s.failed_layer,
    error_summary: s.error_summary,
    message: 'Circuit breaker tripped. Escalating to human.'
  }
}];

// Update Parse Request state for next round via Set node workaround
const s = $input.first().json;
return [{
  json: {
    req_id: s.req_id,
    title: s.title,
    description: s.description || '',
    scope: s.scope,
    round: s.round,
    total_tokens: s.total_tokens,
    start_time: s.start_time,
    max_rounds: s.max_rounds,
    max_duration_ms: s.max_duration_ms,
    max_tokens: s.max_tokens
  }
}];

const s = $input.first().json;
return [{
  json: {
    ...s,
    issue_closed: true
  }
}];

const s = $input.first().json;
return [{
  json: {
    ...s,
    merge_slot_acquired: true
  }
}];

